class Solution:
    def maxPoints(self, points: List[List[int]]) -> int:
        map_p = defaultdict(int)
        result = 0
        for x1, y1 in points:
            y_inter = 0
            for x2, y2 in points:
                if x2 - x1 != 0:
                    m = (y2 - y1) / (x2 - x1)
                    b = y1 - m * x1

                    map_p[(m,b)] += 1
                else:
                    y_inter += 1

            if map_p:
                result = max(result, max(map_p.values()) + 1)
            result = max(result, y_inter)
            map_p = defaultdict(int)

        return result
